  "exercises": [
    {
      "sourceText": "Es ist acht Uhr.",
      "modelAnswer": "Il est huit heures.",
      "alternatives": [
        "Il est huit heures du matin.",
        "Il est huit heures, c'est tout."
      ],
      "keyPoints": [
        "Expression de l'heure en français",
        "Utilisation de 'il est' pour indiquer l'heure",
        "Nombre cardinal : huit"
      ]
    },
    {
      "sourceText": "Die Schule beginnt um neun.",
      "modelAnswer": "L'école commence à neuf heures.",
      "alternatives": [
        "L'école commence à neuf.",
        "À neuf heures, l'école commence."
      ],
      "keyPoints": [
        "Verbe 'commencer' au présent",
        "Préposition 'à' pour les heures",
        "Nombre cardinal : neuf"
      ]
    },
    {
      "sourceText": "Ich stehe um sieben auf.",
      "modelAnswer": "Je me lève à sept heures.",
      "alternatives": [
        "À sept heures, je me lève.",
        "Je me lève à sept."
      ],
      "keyPoints": [
        "Verbe 'se lever' au présent",
        "Préposition 'à' pour les heures",
        "Nombre cardinal : sept"
      ]
    },
    {
      "sourceText": "Das Essen ist um zwölf.",
      "modelAnswer": "Le repas est à midi.",
      "alternatives": [
        "À midi, le repas est prêt.",
        "Le repas est à douze heures."
      ],
      "keyPoints": [
        "Expression 'à midi' pour 12h",
        "Nominalisation du repas : 'le repas'",
        "Utilisation de 'est' au présent"
      ]
    },
    {
      "sourceText": "Ich gehe um fünf schlafen.",
      "modelAnswer": "Je vais me coucher à cinq heures.",
      "alternatives": [
        "À cinq heures, je vais dormir.",
        "Je vais dormir à cinq."
      ],
      "keyPoints": [
        "Verbe 'aller' au présent pour indiquer un futur proche",
        "Expression de l'heure avec 'à'",
        "Nominalisation du sommeil : 'me coucher'"
      ]
    }
  ]
}
